import React from 'react';

const ContactoPage = () => {
  // Define las imágenes y sus URLs destino
  const images = [
    {
      src: '/media/contactoPage/UCBA.png',
      alt: 'Entrada UCB',
      link: 'https://www.ucb.edu.bo/', // Cambia a la URL que quieras
    },
    {
      src: '/media/contactoPage/SIS - H.png',
      alt: 'Logo SIS',
      link: 'https://www.ucb.edu.bo/contacto', // Cambia a la URL que quieras
    },
    {
      src: '/media/contactoPage/IIE - H.png',
      alt: 'Equipo ADM',
      link: 'https://www.ucb.edu.bo/nosotros', // Cambia a la URL que quieras
    },
  ];

  return (
    <main style={styles.page}>
      <div style={styles.container}>
        {/* Título */}
        <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>

        {/* Imágenes con links */}
        <div style={styles.imagesRow}>
          {images.map(({ src, alt, link }, idx) => (
            <a
              key={idx}
              href={link}
              target="_blank"
              rel="noopener noreferrer"
              style={styles.link}
            >
              <img src={src} alt={alt} style={styles.mainImage} />
            </a>
          ))}
        </div>
      </div>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F8F0E3',
    minHeight: '100vh',
    padding: '3rem 1rem',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  },
  container: {
    maxWidth: '100%',
    color: '#052018',
    padding: '0 1rem',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '2rem',
    textAlign: 'center',
    color: '#052018',
  },
  imagesRow: {
    display: 'flex',
    justifyContent: 'center',
    gap: '1.5rem',
    flexWrap: 'wrap',
  },
  link: {
    flex: '1 1 30%', // 3 imágenes alineadas con espacio
    maxWidth: 320,
    textDecoration: 'none',
  },
  mainImage: {
    width: '100%',
    maxHeight: 300,
    objectFit: 'cover',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    transition: 'transform 0.3s ease',
    cursor: 'pointer',
  },
};

export default ContactoPage;
